# Script Name: ADDS-user-audit.ps1
# Author: Ryder Fryling
# Date Created: 3/8/2026
# Synopsis: this script askes for a user then searches the OU structure for that user and displayes output accordingly. #select the format for how you would like to search for the user Write-Host "how would you like to search by: `n 1. By firstname and last name`n 2. By username."
$choice = Read-Host "&gt;" #option to search by first and last name. if ($choice -eq "1") { #gathering first and last names. Write-Host "enter the first and last names of the user that you would like to search `n=========================================================================================================" $Fname = Read-Host "First Name".ToLower() $Lname = Read-Host "Last Name".ToLower() #formatting the input anss a user name $Suser = "$Fname.$Lname" #searching the ADDS $results = Get-ADUser -Filter { Name -eq $Suser } -Properties DisplayName, Department, Title, Enabled, PasswordLastSet #option to search by user name&gt; }elseif ($choice -eq "2") { #input for said username Write-Host "enter the user that you would like to search `n=========================================================================================================" $Suser = Read-Host "&gt;".ToLower() #searching the ADDS $results = Get-ADUser -Filter { Name -eq $Suser } -Properties DisplayName, Department, Title, Enabled, PasswordLastSet #error/misinput handling. }else { Write-Host "invalid input" -BackgroundColor Red $results = "" } #display search results if ($results -ne "") { clear Write-Host "--------------------Account Info-------------------- `n Name : $($results.DisplayName) Department : $($results.Department) Login : $($results.SamAccountName) Title : $($results.Title) PasswordLastSet : $($results.PasswordLastSet)" #displayes if the user account is enabled or not if ($results.Enabled) { Write-Host " Enabled : True" -BackgroundColor Green }else { Write-Host " Enabled : False" -BackgroundColor Red }
#error/misinput handeling }elseif ($results -eq "") { #non-existant user output. }else { Write-Host "The account $Suser does not exist in the domain." -ForegroundColor Red }

