#Get-UserLoginHistory.ps1
#Author: Ryder Fryling #Created: 2026/03/19
#Version 1.0
#Updated: N/A
#Description: This script reports disk space for one or more drives, with output format controlled by a parameter. &lt;#
.SYNOPSIS Retrieves recent user logon events from the Windows Security log. .DESCRIPTION Queries the Security event log for Event ID 4624 (successful logon) and filters by the specified number of days and logon type. Returns the time, account name, and logon type for each matching event. .PARAMETER DaysBack Number of days of history to search. Must be between 1 and 90. Defaults to 7. .PARAMETER LogonType The Windows logon type to filter on. 2 = Interactive (local console), 3 = Network, 10 = RemoteInteractive (RDP). Defaults to all types if not specified. .PARAMETER MaxResults Maximum number of events to return. Defaults to 20. .EXAMPLE .\Get-UserLoginHistory.ps1 Shows the last 7 days of logon events (up to 20 results). .EXAMPLE .\Get-UserLoginHistory.ps1 -DaysBack 30 -LogonType 10 -MaxResults 50 Shows RDP logons from the last 30 days (up to 50 results). Time Account LogonType ---- ------- --------- 3/22/2026 10:23:46 PM bob 10 3/22/2026 10:23:46 PM bob 10
#&gt;
param( [ValidateRange(1, 90)] [int]$DaysBack = 7, [Parameter(Mandatory = $false)] [ValidateSet(2, 3, 10)] [int]$LogonType, [ValidateRange( 1, 500)] [int]$MaxResults = 20 ) #gets the start date $startDate = (Get-Date).AddDays(-$DaysBack) #if a logon is provided it will go this way if ($LogonType) { # gets the data and sorts in in the hash table Get-WinEvent -FilterHashtable @{ LogName = 'Security' Id = 4624 StartTime = $startDate #sorts te maximum of displayed events } -MaxEvents $MaxResults -ErrorAction SilentlyContinue | Where-Object { #sorts the provided logon $_.Properties[8].Value -eq $LogonType } | ForEach-Object { #creates and formats the table [PSCustomObject]@{ Time = $_.TimeCreated Account = $_.Properties[5].Value LogonType = $_.Properties[8].Value } } | Format-Table -AutoSize #if no usere logon is provided --this is exactly the same as above with the exception of the logon filtering being removed } else { Get-WinEvent -FilterHashtable @{ LogName = 'Security' Id = 4624 StartTime = $startDate
} -MaxEvents $MaxResults -ErrorAction SilentlyContinue | ForEach-Object { [PSCustomObject]@{ Time = $_.TimeCreated Account = $_.Properties[5].Value } } | Format-Table -AutoSize }

