# Script Name: Remove-ADUser.ps1
# Author: Danit Kang # Date Created: 03/22/2026 # Date Modified: 03/22/2026 # Synopsis: Removes all Active Directory users recursively from root OU # Retrieves all AD Users recursively and removes them
Get-ADUser -Filter * -SearchBase "OU=Atlas,DC=Corp,DC=Atlas,DC=com" -SearchScope SubTree | Remove-ADUser -Confirm:$false # Validates count of AD Users
$check = (Get-ADUser -Filter * -SearchBase "OU=Atlas,DC=Corp,DC=Atlas,DC=com" -SearchScope SubTree).Count if ($check -ne 0) { Write-Host "User Count: $check" -ForegroundColor Red Write-Host "Failed to Remove All Users" -ForegroundColor Red
}else { Write-Host "User Count: $check" -ForegroundColor Green Write-Host "Successfully Removed All Users" -ForegroundColor Green
}
